function PearlScene() {
  const mountRef = useRef(null);
  useEffect(() => {
    const mount = mountRef.current;
    if (!mount) return;
    const scene = new THREE.Scene();
    const w = mount.clientWidth, h = mount.clientHeight;
    const camera = new THREE.PerspectiveCamera(50, w / h, 0.1, 100);
    camera.position.z = 14;
    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setSize(w, h);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.toneMapping = THREE.NoToneMapping;
    if ("outputColorSpace" in renderer && THREE.SRGBColorSpace) renderer.outputColorSpace = THREE.SRGBColorSpace;
    else if ("outputEncoding" in renderer && THREE.sRGBEncoding) renderer.outputEncoding = THREE.sRGBEncoding;
    mount.appendChild(renderer.domElement);
    // soft pink->white environment for realistic glossy reflections (works in r128 + r0.160)
    let envRT = null, pmrem = null;
    try {
      pmrem = new THREE.PMREMGenerator(renderer);
      const gc = document.createElement("canvas"); gc.width = 32; gc.height = 128;
      const gx = gc.getContext("2d");
      const grad = gx.createLinearGradient(0, 0, 0, 128);
      grad.addColorStop(0, "#fff6f9"); grad.addColorStop(0.45, "#ffdde6"); grad.addColorStop(1, "#f3a8be");
      gx.fillStyle = grad; gx.fillRect(0, 0, 32, 128);
      const envTex = new THREE.CanvasTexture(gc);
      envTex.mapping = THREE.EquirectangularReflectionMapping;
      envRT = pmrem.fromEquirectangular(envTex);
      scene.environment = envRT.texture;
      envTex.dispose();
    } catch (e) {}
    scene.add(new THREE.AmbientLight(0xfff0f4, 0.85));
    const key = new THREE.DirectionalLight(0xffffff, 1.15); key.position.set(5, 8, 8); scene.add(key);
    const fill = new THREE.PointLight(0xffd6e2, 1.5, 60); fill.position.set(-8, -4, 6); scene.add(fill);
    const rim = new THREE.PointLight(0xffffff, 1.3, 60); rim.position.set(0, 6, -10); scene.add(rim);
    const group = new THREE.Group(); scene.add(group);
    const palette = [0xfbd0da, 0xf7b9c8, 0xfcdfe6, 0xf5a8bd, 0xffe9ef];
    const geo = new THREE.SphereGeometry(1, 64, 64);
    const pearls = [];
    for (let i = 0; i < 34; i++) {
      const mat = new THREE.MeshPhysicalMaterial({
        color: palette[i % palette.length],
        roughness: 0.09, metalness: 0.0,
        clearcoat: 1.0, clearcoatRoughness: 0.06,
        reflectivity: 0.6, envMapIntensity: 0.85,
        iridescence: 0.3, iridescenceIOR: 1.3,
        emissive: 0xffc2d2, emissiveIntensity: 0.14,
        transparent: true, opacity: 0.97, depthWrite: true,
      });
      const m = new THREE.Mesh(geo, mat);
      const r = 0.45 + Math.random() * 0.95; m.scale.setScalar(r);
      const bx = (Math.random() - 0.5) * 18, by = (Math.random() - 0.5) * 12, bz = (Math.random() - 0.5) * 8 - 1;
      m.position.set(bx, by, bz);
      m.userData = { speed: 0.25 + Math.random() * 0.5, phase: Math.random() * Math.PI * 2, amp: 0.4 + Math.random() * 0.7, baseX: bx, baseY: by, baseZ: bz, spin: (Math.random() - 0.5) * 0.4, fly: 2 + Math.random() * 6 };
      group.add(m); pearls.push(m);
    }
    let mx = 0, my = 0, tx = 0, ty = 0;
    const onMove = (e) => { tx = (e.clientX / window.innerWidth - 0.5) * 0.6; ty = (e.clientY / window.innerHeight - 0.5) * 0.6; };
    window.addEventListener("pointermove", onMove);
    // scroll-driven cinematic progress (0 at top → 1 after one viewport)
    let sp = 0;
    const onScroll = () => { sp = Math.min(window.scrollY / Math.max(window.innerHeight, 1), 1); };
    onScroll();
    window.addEventListener("scroll", onScroll, { passive: true });
    let raf; const clock = new THREE.Clock();
    const ease = (x) => x * x * (3 - 2 * x);
    const animate = () => {
      const t = clock.getElapsedTime();
      const p = ease(sp);
      pearls.forEach((u2) => {
        const u = u2.userData;
        u2.position.x = u.baseX * (1 + p * 0.5);
        u2.position.y = u.baseY * (1 + p * 0.3) + Math.sin(t * u.speed + u.phase) * u.amp;
        u2.position.z = u.baseZ + p * u.fly;            // pearls drift toward camera (fly-through)
        u2.rotation.x += u.spin * 0.01; u2.rotation.y += u.spin * 0.012;
        u2.material.opacity = 0.92 * (1 - p * 0.85);     // fade out on scroll for a clean handoff
      });
      mx += (tx - mx) * 0.04; my += (ty - my) * 0.04;
      group.rotation.y = mx + p * 0.9;
      group.rotation.x = my + p * 0.25;
      group.rotation.z = Math.sin(t * 0.05) * 0.04;
      camera.position.z = 14 - p * 6;                    // dolly in
      camera.position.y = p * 1.6;
      camera.lookAt(0, 0, 0);
      mount.style.opacity = String(1 - p * 0.9);
      renderer.render(scene, camera); raf = requestAnimationFrame(animate);
    };
    animate();
    const onResize = () => { const nw = mount.clientWidth, nh = mount.clientHeight; camera.aspect = nw / nh; camera.updateProjectionMatrix(); renderer.setSize(nw, nh); };
    window.addEventListener("resize", onResize);
    return () => { cancelAnimationFrame(raf); window.removeEventListener("pointermove", onMove); window.removeEventListener("scroll", onScroll); window.removeEventListener("resize", onResize); geo.dispose(); pearls.forEach((p) => p.material.dispose()); if (envRT) envRT.dispose(); if (pmrem) pmrem.dispose(); renderer.dispose(); if (renderer.domElement.parentNode) renderer.domElement.parentNode.removeChild(renderer.domElement); };
  }, []);
  return <div ref={mountRef} style={{ position: "absolute", inset: 0 }} />;
}

function useReveal(dep) {
  useEffect(() => {
    const els = document.querySelectorAll("[data-reveal]");
    const io = new IntersectionObserver((entries) => {
      entries.forEach((e) => { if (e.isIntersecting) { e.target.classList.add("is-in"); io.unobserve(e.target); } });
    }, { threshold: 0.15 });
    els.forEach((el) => io.observe(el));
    return () => io.disconnect();
  }, [dep]);
}

function Cursor() {
  const ring = useRef(null), dot = useRef(null);
  useEffect(() => {
    if (window.matchMedia("(pointer: coarse)").matches) return;
    let rx = 0, ry = 0, dx = 0, dy = 0;
    const move = (e) => { dx = e.clientX; dy = e.clientY; if (dot.current) dot.current.style.transform = `translate(${dx}px,${dy}px)`; };
    let raf; const loop = () => { rx += (dx - rx) * 0.18; ry += (dy - ry) * 0.18; if (ring.current) ring.current.style.transform = `translate(${rx}px,${ry}px)`; raf = requestAnimationFrame(loop); };
    window.addEventListener("pointermove", move); loop();
    return () => { window.removeEventListener("pointermove", move); cancelAnimationFrame(raf); };
  }, []);
  return (<><div ref={ring} className="cur-ring" /><div ref={dot} className="cur-dot" /></>);
}

function Gallery({ images, blend }) {
  const [i, setI] = useState(0);
  const startX = useRef(null);
  const n = images.length;
  const go = (d) => setI((p) => (p + d + n) % n);
  useEffect(() => { setI(0); }, [images]);
  const down = (e) => { startX.current = e.touches ? e.touches[0].clientX : e.clientX; };
  const up = (e) => {
    if (startX.current == null) return;
    const x = e.changedTouches ? e.changedTouches[0].clientX : e.clientX;
    const dx = x - startX.current;
    if (Math.abs(dx) > 40) go(dx < 0 ? 1 : -1);
    startX.current = null;
  };
  return (
    <div className="gallery" onTouchStart={down} onTouchEnd={up} onMouseDown={down} onMouseUp={up}>
      <div className="ring ring--a" /><div className="ring ring--b" />
      <div className="gallery__track" style={{ transform: `translateX(-${i * 100}%)` }}>
        {images.map((item, idx) => {
          const it = typeof item === "string" ? { src: item } : item;
          return (
            <div className={`gallery__slide ${it.scene ? "gallery__slide--scene" : ""}`} key={idx}>
              <img className={`${blend && !it.scene ? "blend" : ""} ${it.scene ? "scene" : ""}`} src={imgSrc(it.src)} alt="" referrerPolicy="no-referrer" draggable="false" onError={(e) => e.currentTarget.classList.add("img-hidden")} />
            </div>
          );
        })}
      </div>
      {n > 1 && (
        <>
          <button className="gallery__nav gallery__nav--prev" onClick={() => go(-1)} aria-label="Zurück">‹</button>
          <button className="gallery__nav gallery__nav--next" onClick={() => go(1)} aria-label="Weiter">›</button>
          <div className="gallery__dots">
            {images.map((_, idx) => (<button key={idx} className={`dot ${idx === i ? "active" : ""}`} onClick={() => setI(idx)} aria-label={`Bild ${idx + 1}`} />))}
          </div>
        </>
      )}
    </div>
  );
}

function ProductDetail({ product, onClose, onAdd }) {
  const [qty, setQty] = useState(1);
  useEffect(() => { setQty(1); }, [product]);
  if (!product) return null;
  return (
    <div className="modal-wrap" onClick={onClose}>
      <div className="modal" onClick={(e) => e.stopPropagation()}>
        <button className="modal__close" onClick={onClose}>✕</button>
        <div className="modal__media"><Gallery images={product.images || [product.img]} blend={product.blend} /></div>
        <div className="modal__info">
          {product.badge && <span className="badge">{product.badge}</span>}
          <h2 className="h2">{product.name}<br /><em>{product.sub}</em></h2>
          <p className="body">{product.desc}</p>
          <ul className="pills">{product.tags?.map((t) => <li key={t}>{t}</li>)}</ul>
          <div className="modal__use"><strong>Anwendung</strong><p>{product.use}</p></div>
          <div className="modal__buy">
            <div className="qty">
              <button onClick={() => setQty((q) => Math.max(1, q - 1))}>−</button><span>{qty}</span><button onClick={() => setQty((q) => q + 1)}>+</button>
            </div>
            <span className="price">{product.price}</span>
          </div>
          <button className="btn btn--solid btn--full" onClick={() => { onAdd(product, qty); onClose(); }}>In den Warenkorb</button>
          <span className="modal__size">{product.size}</span>
        </div>
      </div>
    </div>
  );
}

function Cart({ open, items, products, onClose, onQty, onRemove }) {
  const lines = items.map((it) => ({ ...it, p: products.find((p) => p.id === it.id) })).filter((l) => l.p);
  const total = lines.reduce((s, l) => s + l.p.priceNum * l.qty, 0);
  return (
    <>
      <div className={`overlay ${open ? "show" : ""}`} onClick={onClose} />
      <aside className={`cart ${open ? "open" : ""}`}>
        <div className="cart__head"><h3>Warenkorb</h3><button onClick={onClose}>✕</button></div>
        <div className="cart__body">
          {lines.length === 0 && <p className="cart__empty">Dein Warenkorb ist noch leer.</p>}
          {lines.map((l) => (
            <div className="cart__item" key={l.id}>
              <div className="cart__thumb"><img className={l.p.blend ? "blend" : ""} src={imgSrc(l.p.img)} alt={l.p.name} referrerPolicy="no-referrer" /></div>
              <div className="cart__meta">
                <h4>{l.p.name}</h4><span>{l.p.sub}</span>
                <div className="qty qty--sm"><button onClick={() => onQty(l.id, -1)}>−</button><span>{l.qty}</span><button onClick={() => onQty(l.id, 1)}>+</button></div>
              </div>
              <div className="cart__right"><span className="cart__price">CHF {l.p.priceNum * l.qty}</span><button className="cart__rm" onClick={() => onRemove(l.id)}>Entfernen</button></div>
            </div>
          ))}
        </div>
        <div className="cart__foot">
          <div className="cart__total"><span>Zwischensumme</span><strong>CHF {total}</strong></div>
          <button className="btn btn--solid btn--full" disabled={lines.length === 0}>Zur Kasse</button>
          <p className="cart__note">Versandkostenfrei ab CHF 39.90</p>
        </div>
      </aside>
    </>
  );
}

function ScrollProgress() {
  const ref = useRef(null);
  useEffect(() => {
    const onScroll = () => {
      const max = document.documentElement.scrollHeight - window.innerHeight;
      const p = max > 0 ? window.scrollY / max : 0;
      if (ref.current) ref.current.style.transform = `scaleX(${p})`;
    };
    onScroll();
    window.addEventListener("scroll", onScroll, { passive: true });
    return () => window.removeEventListener("scroll", onScroll);
  }, []);
  return <div className="scrollbar"><div ref={ref} className="scrollbar__fill" /></div>;
}

